        'value_upfront_title' => 'What to expect before you sign up',
        'value_upfront_text' => 'Start from ₱10,000. Compare fees, payment options, and supported coins. No obligation. 24/7 support if you have questions.',
        'benefits_title' => 'Benefits of investing in cryptocurrency with our investment platform',
        'benefits_card1_title' => 'Variety of payment methods',
