        'benefits_card4_title' => 'Low exchange fees',
        'benefits_card4_text' => 'Transparent pricing, up to 45% off service fees. No hidden charges.',
        'app_title' => 'EquiLoomPRO mobile app smart cryptocurrency investments on the go',
        'app_text' => 'Experience full-featured crypto investment functionality right from your phone. The EquiLoomPRO Mobile App is built for fast, secure, and seamless crypto investments—anytime, anywhere.',
        'app_feature1_title' => 'All-in-one functionality',
        'app_feature1_text' => 'Enjoy the same powerful features as the desktop version—buy, sell, and invest in crypto on the move.',
        'app_feature2_title' => 'User-friendly & fast',
        'app_feature2_text' => 'Optimized for both beginners and pros. Smooth navigation, instant transactions.',
        'top10_title' => 'Top 10 cryptocurrencies to invest in now',
        'top10_all_cryptocurrencies' => 'All cryptocurrencies',
        'btn_buy_now' => 'Invest now',
        'safe_title' => 'Licensed, secure and fast way to invest in crypto',
        'safe_text' => 'Interested in Bitcoin (BTC) and other digital assets? EquiLoomPRO is a Philippines-registered platform that lets you buy crypto with your card or GCash in minutes. Transparent fees, PCI-compliant processing, 24/7 support. Your data is protected under the Data Privacy Act of 2012. Get started from ₱10,000.',
        'faq_title' => 'Frequently asked questions',
        'faq_q1' => 'Can I Invest in Crypto with a Credit Card?',
        'faq_a1' => 'Absolutely. You can invest in crypto with credit and debit cards (simplified KYC). Use popular payment methods to your liking. No cash advance (e.g., to redeem a voucher or gift card) is required.',
        'faq_q2' => 'How Do I Invest in Crypto with a Credit Card?',
        'faq_a2' => 'To invest in crypto with a credit card at EquiLoomPRO, create a user account (or a merchant account for businesses), complete basic info verification, use the EquiLoomPRO widget to place an order, and convert fiat to crypto online.',
        'faq_q3' => 'What Cryptocurrencies Do You Support?',
        'faq_a3' => 'With EquiLoomPRO, you can buy, sell, invest in, send, receive, deposit, store, and HODL, all trending and popular coins and tokens. The list of supported coins includes BTC, ETH, USDT, XRP, USDC, MATIC, STND, TRX, ELK, DOGE, BCH, ADA, LTC, etc.',
        'faq_q4' => 'Where to Invest in Bitcoin with a Credit Card?',
        'faq_a4' => 'EquiLoomPRO offers a straightforward way to invest in Bitcoin with a credit card: Philippines-registered, card and GCash support, transparent fees, and 24/7 support. Suitable for both crypto enthusiasts and experienced investors.',
        'faq_q5' => 'Can I Sell Crypto Online?',
        'faq_a5' => 'Yes. EquiLoomPRO is a full-featured crypto investment platform that supports all directions (crypto purchases, sales, and investments). You can sell virtual currencies at EquiLoomPRO and receive fiat to your Philippine bank account via bank transfer or GCash. It is typically best suited for large-volume transactions.',
        'faq_cta' => 'Could not find the answer to your question? Describe your issue in live chat',
        'about__hero_title' => 'Safe, Transparent & Fair Investments',
        'about__hero_text' => 'EquiLoomPRO is a trusted Philippines-registered platform for investing in cryptocurrencies online, offering compliant financial services, full legal compliance, and secure, fairly priced crypto investments.',
        'about__hero_btn' => 'Invest in / Sell Crypto',
        'about__how_it_works_title' => 'How it Works Step-by-Step',
        'about__how_it_works_step1_title' => 'Register on EquiLoomPRO',
        'about__how_it_works_step1_text' => 'Complete registration and get verified to raise your account purchase limit.',
        'about__how_it_works_step2_title' => 'Invest in / Manage Crypto',
        'about__how_it_works_step2_text' => 'Choose currency, enter the amount, your wallet address & make payment.',
        'about__how_it_works_step3_title' => 'Get crypto to your wallet address!',
        'about__how_it_works_step3_text' => 'The funds will be sent to your wallet address within minutes!',
        'about__major_advantages_title' => 'Major Advantages',
        'about__advantage_1_title' => 'Fast Processing',
        'about__advantage_1_text' => 'One of the fastest and easiest ways to buy or convert crypto instantly and securely.',
        'about__advantage_2_title' => 'High Spending Limits',
        'about__advantage_2_text' => 'High purchase limits with streamlined verification. Philippines-registered partner, clear KYC process, no unnecessary paperwork.',
        'about__advantage_3_title' => 'WYSIWYG Algorithm',
        'about__advantage_3_text' => 'Receive exactly the same amount you have paid for — every single time.',
        'about__panel_title' => 'First-Class Investment Services',
        'about__panel_text' => 'equiloom-pro.co simplifies crypto investing: buy Bitcoin, Ethereum, Litecoin and other leading coins in a few clicks. Visa, Mastercard, GCash. Philippines-registered partner, PCI-compliant processing, transparent fees.',
        'login__title' => 'Get in touch',
        'login__text' => 'We are here to answer any questions you may have about equiloom-pro.co.',
        'privacy__subtitle' => 'This Privacy Policy discloses how equiloom-pro.co collects, protects, uses and shares personal information gathered from platform users on the website in accordance with the Data Privacy Act of 2012.',
        'privacy__title_1_general' => '1. General',
        'privacy__text_1_general_p1' => 'equiloom-pro.co (hereinafter also referred to as “we,” “us,” “our,” "website,” or “EquiLoomPRO”) is committed to protecting and respecting website visitor’s (hereinafter also referred to as “you” or “your”) privacy in accordance with this Privacy Policy (hereinafter also referred to as “Policy”). We highly value your interest in our website and services offered on it. Your privacy is equally important to us. We would like you to feel at ease with how we use and share your personal information.',
        'privacy__text_1_general_p2' => 'equiloom-pro.co is a website operated by the company EquiLoomPRO PH Inc (Ayala Avenue, Makati City 1226, Philippines). Under the Data Privacy Act of 2012, we have a legal duty to protect all personal information we collect from you. If you do not agree with the terms of this Policy, please do not use the website services.',
        'privacy__text_1_general_p3' => 'The website may contain translations of the English version of the content available on equiloom-pro.co. These translations are provided only as a convenience. In the event of any conflict between the English language version and the translated version, the English language version shall take precedence.',
        'privacy__title_2_definitions' => '2. Definitions',
        'privacy__text_2_service_switchere' => 'Service or “equiloom-pro.co” All the services offered on the website equiloom-pro.co',
        'privacy__subtitle_personal_data' => 'Personal Data',
        'privacy__text_personal_data' => 'Personal Data means any information about a living individual who can be identified by this information (or from other information either in our possession or likely to come into our possession).',
        'privacy__subtitle_usage_data' => 'Usage Data',
        'privacy__text_usage_data' => 'Usage Data is data collected automatically, either generated by the use of the service or from the service infrastructure itself (for example, the duration of a page visit, device identification, operating system, browser type, etc.).',
        'privacy__subtitle_cookies' => 'Cookies',
        'privacy__text_cookies' => 'Cookies are small pieces of data stored on your device (desktop computer, tablet PC or mobile device).',
        'privacy__subtitle_data_controller' => 'Data Controller',
        'privacy__text_data_controller' => 'Data Controller means the natural or legal person who determines the purposes for which and the manner in which any personal information is, or is to be, processed. For the purpose of this Privacy Policy, we are the Data Controller of your Personal Data.',
        'privacy__subtitle_data_subject' => 'Data Subject (or User/Customer)',
        'privacy__text_data_subject' => 'Data Subject is any living individual who uses the services provided on equiloom-pro.co and is the subject of Personal Data.',
        'privacy__subtitle_partner' => 'Partner',
        'privacy__text_partner' => 'EquiLoom Payments PH Inc (reg. Number 987654321), Ayala Avenue, Makati City 1226, Philippines and its affiliated entities, who offer virtual currency services on our Website.',
        'privacy__title_3_information_collection_use' => '3. Information Collection and Use',
        'privacy__text_3_intro' => 'Personal information may be collected in a number of ways when you visit our website. Types of data collected may include:',
        'privacy__subtitle_3_personal_data' => 'Personal Data',
        'privacy__text_3_personal_data_p1' => 'While using the equiloom-pro.co website and services offered on the website, we may ask you to provide us with certain personally identifiable information that can be used to contact or identify you. We use personal information to offer you the services you explicitly solicited for, to facilitate safe services, survey customer interest in all our services, update you on offers, services, products, customize your personal experience, safeguard us against any fraud, error and other kinds of criminal activities. We may periodically request personally identifiable information may include, but is not limited to:',
        'privacy__personal_data_item_1' => 'Email address and/or other contact information;',
        'privacy__personal_data_item_2' => 'Date of Birth;',
        'privacy__personal_data_item_3' => 'Cookies and usage data;',
        'privacy__personal_data_item_4' => 'Authentication information. This is information that can be used to authenticate your identity on equiloom-pro.co such as username, password and/or other account information;',
        'privacy__personal_data_item_5' => 'Shared information. You may share your personal information such as family details, life goals and events with us in the course of our cooperation;',
        'privacy__personal_data_item_6' => 'Other information described in the Terms of Use or other legal documents.',
        'privacy__text_3_personal_data_p2' => 'Whenever you are using the virtual currency services of our Partner, which are offered on our website, our Partners might request you to provide additional information. Please be informed, that you are providing that information directly to our Partner and they process it in accordance with their Privacy Policy.',
        'privacy__subtitle_3_usage_data' => 'Usage Data',
        'privacy__text_3_usage_data' => 'We may also collect information how equiloom-pro.co is accessed and used ("Usage Data"). When you visit our website, some information is automatically collected through the use of log files, such as your computer’s Internet Protocol (IP) address, your computer’s operating system (OS), the browser type, the address of a referring website and your activity on the website. We use this information for purposes such as analyzing trends, administering the website, improving customer service, diagnosing problems with our servers, etc.',
        'privacy__subtitle_3_tracking_cookies' => 'Tracking Technologies and Cookies',
        'privacy__text_3_tracking_cookies' => 'equiloom-pro.co uses cookies and similar tracking technologies to track activity on the site and store certain information. Cookies are small text files containing a small amount of data which may include a unique anonymous identifier. Cookies are sent from the site to your browser and stored on your device. To collect and track information and to improve and analyze equiloom-pro.co services, we also use the following tracking technologies: beacons, tags and scripts. You can set your browser to refuse all cookies or to indicate when a cookie is being sent. However, if you do not accept cookies, some of equiloom-pro.co services may not function properly. Examples of cookies we use: session cookies — to operate the site during a single session; preference cookies — to remember your preferences and various settings; security cookies — for security purposes. All collected cookies are encrypted so that no third party can intercept or use the information contained therein.',
        'privacy__title_4_use_of_data' => '4. Use of Data',
        'privacy__text_4_intro' => 'equiloom-pro.co uses the collected data for various purposes:',
        'privacy__use_of_data_item_1' => 'To allow you to register an account on equiloom-pro.co;',
        'privacy__use_of_data_item_2' => 'To identify you as a customer and distinguish you from other users of our service;',
        'privacy__use_of_data_item_3' => 'To provide you with functional, secure and personalized services on a regular basis;',
        'privacy__use_of_data_item_4' => 'To notify you of changes and upgrades offered on equiloom-pro.co;',
        'privacy__use_of_data_item_5' => 'To allow you to participate in promotional campaigns run by equiloom-pro.co when you choose to do so;',
        'privacy__use_of_data_item_6' => 'To send information for marketing purposes and keep you informed about the latest product advertisements and upcoming promotional events;',
        'privacy__use_of_data_item_7' => 'To provide professional and timely customer care services and better understand you as a customer or visitor;',
        'privacy__use_of_data_item_8' => 'To monitor the use of equiloom-pro.co services;',
        'privacy__use_of_data_item_9' => 'To detect, prevent and eliminate technical problems;',
        'privacy__use_of_data_item_10' => 'To prevent losses and/or fraud;',
        'privacy__use_of_data_item_11' => 'To comply with all mandatory legal obligations.',
        'privacy__title_5_legal_basis_gdpr' => '5. Legal Basis for Processing Personal Data under Data Privacy Act',
        'privacy__text_5_p1' => 'If you are a resident of the Philippines or your IP address is from there, the legal basis for equiloom-pro.co to collect and use the personal information described in this Privacy Policy depends on the Personal Data we collect and the specific context in which we collect it. In accordance with the Data Privacy Act of 2012, we rely on appropriate technical and organisational measures to help prevent unauthorised access to your information and to ensure that data is held securely.',
        'privacy__text_5_p2' => 'equiloom-pro.co may process your Personal Data for the following reasons:',
        'privacy__legal_basis_item_1' => 'We need to perform a contract with you;',
        'privacy__legal_basis_item_2' => 'You have given us permission to do so;',
        'privacy__legal_basis_item_3' => 'The processing is in our legitimate interests and does not override your rights;',
        'privacy__legal_basis_item_4' => 'To comply with all applicable laws and regulations in the Philippines.',
        'privacy__title_6_retention' => '6. Retention of Data',
        'privacy__text_6_p1' => 'equiloom-pro.co will retain your Personal Data only for as long as is necessary for the purposes set out in this Privacy Policy. We will retain and use your Personal Data to the extent necessary to comply with our legal obligations (for example, if we are required to retain your data to comply with applicable laws), resolve disputes, and enforce our legal agreements and policies.',
        'privacy__text_6_p2' => 'equiloom-pro.co will also retain Usage Data for internal analysis purposes. Usage Data is generally retained for a short period of time, except when this data is used to strengthen the security or to improve the functionality of our Services, or we are legally obligated to retain this data for longer periods. By registering on equiloom-pro.co, you agree to our retention of your Personal Data.',
        'privacy__title_7_transfer' => '7. Transfer of Data',
        'privacy__text_7_p1' => 'Your information, including Personal Data, may be transferred to — and maintained on — computers located outside of your state, province, country or other governmental jurisdiction where the data protection laws may differ than those from your jurisdiction. Please note that we may transfer data, including Personal Data, outside of your jurisdiction (including outside the Philippines if that is your jurisdiction) and process it there. Your consent to this Privacy Policy followed by your submission of such information represents your agreement to that transfer. equiloom-pro.co will take all steps reasonably necessary to ensure that your data is treated securely and in accordance with this Privacy Policy and no transfer of your Personal Data will take place to an organisation or a country unless there are adequate controls in place including the security of your data and other personal information. Furthermore, we may transfer Personal Data to a successor or assignee and/or other entity to which all and/or certain rights and obligations are assigned in the event of assignment/transfer of rights and/or obligations or liquidation or termination of the contract with you or otherwise. equiloom-pro.co ensures adequate protection of your Personal Data in the event of such transfer or assignment, and the successor/assignee will retain all of your rights relating to Personal Data.',
        'privacy__title_8_disclosure' => '8. Disclosure of Data',
        'privacy__text_8_p1' => 'In certain circumstances, we rely on our legitimate business interests to collect and use your Personal Data. In such cases, we have conducted a balancing test to carefully consider the impact of the processing on your interests, rights and freedoms. We will only process if we are satisfied that there is no negative impact on you. equiloom-pro.co may disclose your Personal Data in good faith if it believes such action is necessary:',
        'privacy__disclosure_item_1' => 'To comply with a legal obligation;',
        'privacy__disclosure_item_2' => 'To protect and defend the rights or property of equiloom-pro.co or its clients;',
        'privacy__disclosure_item_3' => 'To prevent or investigate any potential wrongdoing in connection with equiloom-pro.co services;',
        'privacy__disclosure_item_4' => 'To protect the personal safety of equiloom-pro.co users or the public;',
        'privacy__disclosure_item_5' => 'To protect against legal liability.',
        'privacy__text_8_p2' => 'Except as described in this Privacy Policy, equiloom-pro.co will not share your Personal Information with third parties unless requested by you, you have consented to such disclosure, or the disclosure is required or authorised by law.',
        'privacy__title_9_security' => '9. Security of Data',
        'privacy__text_9_p1' => 'In accordance with the Data Privacy Act of 2012, we rely on appropriate technical and organisational measures to help prevent unauthorised access to your information and to ensure that data is held securely. The security of your data is important to us, but remember that no method of transmission over the Internet, or method of electronic storage is 100% secure. While we strive to use commercially acceptable means to protect your Personal Data, we cannot guarantee its absolute security. Security measures include firewalls, data encryption, and access authorisation controls. While we are committed to securing our site and services, you are responsible for securing your passwords and account registration information and maintaining their confidentiality and for verifying the accuracy and currency of the Personal Data we hold about you.',
        'privacy__title_10_dnt_caloppa' => '10. Do Not Track Signals under CalOPPA',
        'privacy__text_10_p1' => 'We do not support “Do Not Track” (“DNT”). DNT is a preference you can set in your web browser to inform websites that you do not want to be tracked. You can enable or disable DNT by visiting the Preferences or Settings page in your browser.',
        'privacy__title_11_rights_gdpr' => '11. Data Protection Rights under Data Privacy Act',
        'privacy__text_11_p1' => 'If you are a resident of the Philippines, you have certain data protection rights. equiloom-pro.co aims to take reasonable steps to allow you to correct, amend, delete, or limit the use of your Personal Data. However, we grant the same rights to all users.',
        'privacy__text_11_p2' => 'If you wish to be informed what Personal Data we hold about you and if you want it to be removed from our systems, please contact us. We will make every effort to do so as soon as possible unless it is not currently possible due to services provided to you on equiloom-pro.co. In such case, we will fulfil your request after fulfilling all obligations under these services.',
        'privacy__text_11_p3' => 'Under certain circumstances, you have the following data protection rights:',
        'privacy__rights_item_1' => 'The right to access the information we hold about you or update or delete it;',
        'privacy__rights_item_2' => 'The right to rectification;',
        'privacy__rights_item_3' => 'The right to object;',
        'privacy__rights_item_4' => 'The right to restriction;',
        'privacy__rights_item_5' => 'The right to data portability;',
        'privacy__rights_item_6' => 'The right to withdraw consent. You also have the right to withdraw your consent at any time where equiloom-pro.co relied on your consent to process your personal information (except where exceptions apply).',
        'privacy__text_11_p4' => 'Please note that we may ask you to verify your identity before responding to such requests.',
        'privacy__text_11_p5' => 'You have the right to lodge a complaint with the National Privacy Commission (NPC) regarding our collection and use of your Personal Data. For more information, please contact your local data protection authority in the Philippines.',
        'privacy__title_12_service_providers' => '12. Service Providers',
        'privacy__text_12_p1' => 'We may employ third-party companies and individuals to facilitate equiloom-pro.co (hereinafter referred to as the "Service Providers"), to provide equiloom-pro.co on our behalf, to perform equiloom-pro.co -related services or to assist us in analyzing how the website is used. These third-parties have access to your personal data to the extent of performance of these tasks on our behalf and are obliged not to disclose or use it for any other purpose.',
        'privacy__title_13_links' => '13. Links to Other Websites',
        'privacy__text_13_p1' => 'equiloom-pro.co website may include links to third-party websites, plug-ins and applications. Clicking on third-party links or enabling those connections may allow third parties to collect or share data about you. We do not control such third-party websites and, when you leave our website, we encourage you to read Privacy Policy of every website you visit. We have no control over and assume no responsibility for the content, privacy policies or practices of any third-party sites or services.',
        'privacy__title_14_children' => '14. Protecting Children’s Privacy',
        'privacy__text_14_p1' => 'equiloom-pro.co’s products and services are for a general audience and not aimed at children under the age of 18 and we do not knowingly collect Personal information from such individuals. If we obtain actual knowledge that we have collected personal data from a child under the age of 18, we will promptly delete it, unless we are legally obligated to retain such data. Contact us directly via the contact form if you believe that we have mistakenly or unintentionally collected information from a child under the age of 18.',
        'privacy__title_15_contact_users' => '15. Establishing Contact with Us and with Other Users',
        'privacy__text_15_p1' => 'equiloom-pro.co enables you to establish contact with us. It is possible, for example, by sending an email to us, or any message via the permitted message service (in accordance with Terms of Use). The information you provide when contacting us is stored to process the request and, where appropriate, for the subsequent correspondence.',
        'privacy__text_15_p2' => 'We do not disclose your personal information to any other equiloom-pro.co users. We will not be liable for any use or misuse of the transactional data by others, but you must inform us of any misuse of equiloom-pro.co that you have become aware of. You are solely responsible for your interactions with other equiloom-pro.co users. We reserve the right, but have no obligation, to monitor disputes between you and other users.',
        'privacy__title_16_governing_law' => '16. Governing Law and Jurisdiction',
        'privacy__text_16_p1' => 'Any disputes concerning this Privacy Policy will be governed by the laws of the Philippines without regard to any principles of conflicts of law. The courts of the Philippines will have exclusive jurisdiction over any claims arising out of or related to this Privacy Policy.',
        'privacy__title_17_registration' => '17. Registration Function',
        'privacy__text_17_p1' => 'You can register as a user of our equiloom-pro.co service on the relevant website page. The received data will be used in operation of our equiloom-pro.co services, as well as to inform you about changes in the scope of our equiloom-pro.co services, or any technical changes or for other messages (via email). Registration at equiloom-pro.co includes the entry of the following data:',
        'privacy__registration_item_1' => 'Email address;',
        'privacy__registration_item_2' => 'Password;',
        'privacy__registration_item_3' => 'Date of Birth.',
        'privacy__text_17_p2' => 'Besides, the IP address used for registration, as well as the date of registration, are securely stored in order to prevent the abuse of registration. By adding information from social networking profiles for equiloom-pro.co registration, we receive information from the social network (profile ID, First Name, Last Name, other data according to terms and conditions of social networks). You agree with processing of your social networking information during registration.',
        'privacy__title_18_access_data' => '18. Access Data/Server Log Files',
        'privacy__text_18_p1' => 'Details of your visit to our equiloom-pro.co website are stored in a log file (the so-called "Server Log File"). We collect (or our internet provider servers) the following data on each access to equiloom-pro.co:',
        'privacy__server_log_item_1' => 'IP address of the accessing computer;',
        'privacy__server_log_item_2' => 'Name of the file requested;',
        'privacy__server_log_item_3' => 'Date and time of the request;',
        'privacy__server_log_item_4' => 'Amount of data transmitted;',
        'privacy__server_log_item_5' => 'Notification of successful request;',
        'privacy__server_log_item_6' => 'Browser type and version along with the operating system used;',
        'privacy__server_log_item_7' => 'Referrer URL;',
        'privacy__server_log_item_8' => 'Requesting provider;',
        'privacy__server_log_item_9' => 'Screen resolution.',
        'privacy__text_18_p2' => 'The log data is used by us only for statistical analysis in the context of operation of equiloom-pro.co. In case of illegal use of our services, the log data also may serve as a resolution in the eventuality of any violation of the law.',
        'privacy__title_19_monitoring' => '19. Monitoring and Recording',
        'privacy__text_19_p1' => 'We may monitor, record, store and use any telephone, email or other means of communication with you to check any instructions given to us, for instructional purposes, crime prevention, and in order to improve the quality of our Customer Care Team service.',
        'privacy__title_20_consent' => '20. Consent',
        'privacy__text_20_p1' => 'By registering as a user of equiloom-pro.co, you consent to the terms of Privacy Policy without any exclusions or reservations.',
        'terms__subtitle' => 'These Terms of Use govern your access to and use of the equiloom-pro.co website.',
        'terms__title_1_general_terms' => '1. General Terms',
        'terms__text_1_general_terms' => 'Please read these Terms of Use (hereinafter referred to as "Terms") carefully before using the equiloom-pro.co website https://equiloom-pro.co/ (hereinafter referred to as "equiloom-pro.co", "EquiLoomPRO", "website", "site", "service", "us", "we" or "our") owned and operated by company EquiLoomPRO PH Inc (reg. number 123456789) with a registered address Ayala Avenue, Makati City 1226, Philippines. EquiLoomPRO PH Inc is incorporated under the laws of the Philippines and operates under the laws of the Philippines. "User", "you" and "you\'re" refer to you, the natural person (individual) or legal person (entity) accessing the website, using our services through https://equiloom-pro.co/ and accepting these Terms. Your access and use of the website is conditioned on your acceptance of and compliance with these Terms of Use.',
        'terms__title_2_definitions' => '2. Definitions',
        'terms__def_creator' => 'Creator: a person who is listing its NFTs for sale via NFT Platform.',
        'terms__def_nft' => 'NFT: blockchain asset defining a non-fungible token, on an underlying blockchain that represents ownership of images, videos, audio files, and other forms of media or ownership of physical or digital property.',
        'terms__def_nft_checkout' => 'NFT Checkout: a technological solution offered by EquiLoomPRO that facilitates the purchase and sale of NFTs with integrated third-party payment methods.',
        'terms__def_partner' => 'Partner: EquiLoom Payments PH Inc (reg. Number 987654321), Ayala Avenue, Makati City 1226, Philippines and its affiliated entities.',
        'terms__def_payment_processors' => 'Payment Processors: refers to any licensed third-party entity or infrastructure facilitating the collection, processing, or conversion of fiat payments on behalf of Users for the purpose of acquiring NFTs on the Platform.',
        'terms__def_switchere' => 'EquiLoomPRO: EquiLoomPRO PH Inc (reg. number 123456789) with a registered address Ayala Avenue, Makati City 1226, Philippines.',
        'terms__label_services' => 'Services:',
        'terms__services_listitem_1' => 'The ability to access the buy and sell services of virtual currency through the EquiLoomPRO website provided by the Partner and using the Partner\'s and its affiliated entities widget (Referral Services). EquiLoomPRO does not process the transactions related to the purchase or sale of cryptocurrency, nor does it hold your assets, as it is part of the service provided by our Partner, whose services are accessible via our website.',
        'terms__services_listitem_2' => 'NFT platform that allows individuals and entities to mint, manage, list, promote, purchase and sell non-fungible tokens (NFTs) on supported blockchain networks (NFT Platform). The NFT Platform does not take possession of, or exert control over, Users\' NFTs or wallet keys. However, EquiLoomPRO integrates directly with Payment Processors to facilitate purchases of NFTs through a secure checkout interface. EquiLoomPRO is not a bank, exchange, broker-dealer, or licensed financial service provider.',
        'terms__def_user' => 'User: Any individual or entity accessing or using the EquiLoomPRO website and services offered on the Website.',
        'terms__def_widget' => 'Widget: The virtual currency exchange widget provided by the Partner or its affiliated entities on the website of EquiLoomPRO.',
        'terms__def_royalties' => 'Royalties: means the percentage of revenue embedded into a smart contract entitling Creators to a portion of the resale price of their NFTs.',
        'terms__title_3_acceptance' => '3. Acceptance of Terms',
        'terms__text_3_acceptance_1' => 'By using the EquiLoomPRO website and Services, you agree to be bound by these Terms of Use. EquiLoomPRO reserves the right to modify these Terms at any time. Any changes will be posted on our website, and your continued use of the services constitutes acceptance of the modified terms. When accessing and using our Partner\'s services for the purchase or sale of virtual currencies, you agree to be simultaneously bound by our Partner\'s Terms of Use. In case of contradictions, Partner\'s Terms of Use shall prevail.',
        'terms__text_3_acceptance_2' => 'You understand, acknowledge and accept the risk of loss in investing or holding any Cryptocurrency (like Bitcoin) can be substantial. You should therefore carefully consider whether investing or holding Bitcoin or any other Cryptocurrency is suitable for you in light of your financial condition. In considering whether to invest in or hold Cryptocurrency, you should be aware that:',
        'terms__risk_listitem_1' => 'When you buy, sell or transfer Cryptocurrency you are dealing with a digital asset. This means that, like any other digital system, Cryptocurrencies are at risk of being hacked or affected by technical problems. This could result in you losing your Cryptocurrency or delaying your ability to sell, transfer or spend it;',
        'terms__risk_listitem_2' => 'The price or value of a Cryptocurrency can change rapidly, decrease and potentially even fall to zero. Factors that may affect the value of a Cryptocurrency include a change in governing regulation, introduction of new Cryptocurrencies, or a change to how a Cryptocurrency works.',
        'terms__text_3_acceptance_3' => 'You acknowledge that we are not responsible for safeguarding or holding your Cryptocurrency, or any private keys or other security information needed to access your Cryptocurrency and that we are not responsible for any loss of Cryptocurrency resulting from theft, loss, or mishandling of Cryptocurrency private keys or other security information outside its control.',
        'terms__text_3_acceptance_4' => 'The Services provided to you by EquiLoomPRO are not regulated by the Bangko Sentral ng Pilipinas (BSP) and you have no recourse to the financial consumer protection mechanisms.',
        'terms__text_3_acceptance_5' => 'Notwithstanding anything to the contrary in this Agreement, if you are using the NFT Platform and are purchasing an NFT from a third party, EquiLoomPRO may facilitate the purchase and delivery of the NFT to a Wallet indicated by you.',
        'terms__text_3_acceptance_6' => 'We do not endorse any NFT in any way. We do not verify the authenticity of and do not review (or approve) any NFT. NFT sellers may make claims about intellectual property ownership, rarity and uniqueness, and value. It is solely your responsibility to investigate and determine the authenticity of any NFT you are considering buying, along with the accuracy of the claims made by the NFT seller. The NFT seller also determines the price, and that price may not be the true market value of the NFT. The rarity and true market value of the NFT may be subject to change, especially if minting is ongoing. EquiLoomPRO makes no representations with respect to any NFT to be purchased. You should not assume that purchasing an NFT gives you any legal rights beyond mere ownership of the underlying blockchain asset. EquiLoomPRO makes no representations as to any auxiliary rights, benefits or rewards supposedly accompanying any NFT.',
        'terms__text_3_acceptance_7' => 'A transaction between a buyer and a seller takes place in a peer-to-peer fashion on either on-chain or through Payment Processors. We do not guarantee that you will receive your NFT, as there are a number of reasons why transactions may fail. For example, network congestion, a technical blockchain issue or another buyer purchases that NFT before your transaction completes on the blockchain. In case your transaction fails, EquiLoomPRO will pay for any gas fees included in the transaction.',
        'terms__title_4_eligibility' => '4. Eligibility',
        'terms__text_4_eligibility_1' => 'You may use the Services only if you satisfy all of the following requirements at the time of access:',
        'terms__eligibility_listitem_1' => 'You are a natural person who is at least 18 years old and have the full legal capacity to enter into binding contracts under the law of the Philippines;',
        'terms__eligibility_listitem_2' => 'You are not accessing the Services from, or on behalf of, an individual or entity in a jurisdiction subject to sanctions or export controls imposed by the United Nations, European Union, United States (including OFAC), or other competent authorities;',
        'terms__eligibility_listitem_3' => 'You are not listed on any international or national sanctions list, watchlist, or registry of prohibited persons or entities;',
        'terms__eligibility_listitem_4' => 'You are not engaging in prohibited conduct under these Terms of Use or local law, including fraudulent use of payment systems or the unauthorized use of third-party content;',
        'terms__eligibility_listitem_5' => 'You are using the Services for lawful, personal, or commercial purposes, and not in violation of intellectual property rights, tax laws, AML/CTF laws, or consumer protection regulations.',
        'terms__text_4_eligibility_2' => 'By accessing our Partner\'s services via our Website, you might be required to satisfy additional requirements in order to receive our Partner\'s services.',
        'terms__text_4_eligibility_3' => 'EquiLoomPRO reserves the right in its sole discretion to block, suspend, or restrict access from any IP address, wallet, payment source, or region that is believed to be in violation of eligibility requirements or presents elevated compliance, legal, or reputational risk.',
        'terms__title_5_registration' => '5. Registration and Account Security',
        'terms__text_5_registration_1' => 'To use the Services offered by EquiLoomPRO or by our Partner on our website, you may be required to create an account. By creating an account you agree to:',
        'terms__registration_listitem_1' => 'Provide accurate and complete information during registration.',
        'terms__registration_listitem_2' => 'Maintain the security of your account and password.',
        'terms__registration_listitem_3' => 'Notify EquiLoomPRO immediately of any unauthorized use of your account.',
        'terms__registration_listitem_4' => 'Be responsible for all activities that occur under your account.',
        'terms__title_6_use_of_services' => '6. Use of Services',
        'terms__text_6_use_of_services_1' => 'You agree to use the Services only for lawful purposes and in accordance with these Terms of Use and the Terms of Use of our Partner and applicable regulations. You shall not, under any circumstances, directly or indirectly engage in any of the following prohibited activities:',
        'terms__prohibited_listitem_1' => 'Uploading, minting, listing, or linking NFTs that contain illegal content, stolen assets, unauthorized copyrighted material, hate speech, deepfakes, or personal identifying information (PII) without consent;',
        'terms__prohibited_listitem_2' => 'Creating misleading listings, counterfeit NFTs, or conducting wash trading, price manipulation, or coordinated shilling;',
        'terms__prohibited_listitem_3' => 'Attempting to artificially inflate the value, price, or popularity of an NFT, Creator, or collection through automated bidding, self-trading, or other deceptive tactics;',
        'terms__prohibited_listitem_4' => 'Circumventing access controls, rate limits, or using automated scripts, bots, or scrapers without prior authorization from EquiLoomPRO;',
        'terms__prohibited_listitem_5' => 'Transmitting malware, phishing attempts, denial-of-service attacks, or otherwise interfering with the normal operation of the Platform;',
        'terms__prohibited_listitem_6' => 'Using NFTs to represent securities, profit-sharing agreements, tokenized debt, or fractionalized ownership in real-world assets in violation of applicable securities laws;',
        'terms__prohibited_listitem_7' => 'Using the Platform in connection with unlawful fundraising activities, money laundering, terrorism financing, or sanctioned persons/entities.',
        'terms__prohibited_listitem_8' => 'Use our Partner\'s offered services on behalf of someone else.',
        'terms__text_6_use_of_services_2' => 'If you are a Creator, you acknowledge that EquiLoomPRO reserves its right to limit or deny use of its Services or listing and sale of any NFTs at its sole discretion without the obligation to provide a legal justification.',
        'terms__title_7_transactions' => '7. Transactions',
        'terms__text_7_transactions_1' => 'All transactions conducted through the EquiLoomPRO website using our Partner\'s widget are subject to these Terms of Use, our Partner\'s Terms of Use, and any applicable laws and regulations. EquiLoomPRO does not guarantee the availability of any virtual currency. Our Partner reserves the right to decide at its own discretion to refuse any transaction at its discretion in accordance with its Terms of Use as well as any applicable Laws and Regulations. Users are fully responsible for ensuring the accuracy of the transaction details before submitting. Please bear in mind that any purchase and sale transactions of virtual currency are fully processed by our Partner and EquiLoomPRO just grants you the right to access such services. Any chargebacks and refunds are processed by our Partner and are subject to our Partner\'s refund and chargeback policy.',
        'terms__text_7_transactions_2' => 'All transactions related to NFT Platform are carried out by one or more Payment Processors.',
        'terms__text_7_transactions_3' => 'You understand and acknowledge that:',
        'terms__transactions_listitem_1' => 'EquiLoomPRO does not store or access your private keys, recovery phrases, or wallet credentials;',
        'terms__transactions_listitem_2' => 'You are solely responsible for securing access to your wallet, regardless of the interface or device used;',
        'terms__transactions_listitem_3' => 'Wallet transactions are broadcast directly to public blockchain networks and are irreversible once confirmed;',
        'terms__transactions_listitem_4' => 'Fiat payments are processed by licensed financial intermediaries, and EquiLoomPRO is not liable for delays, failures, or reversals due to credit card rejections, KYC rejections, bank decline codes, or card network rules;',
        'terms__transactions_listitem_5' => 'You may be required to complete identity verification (KYC) before using certain fiat features, pursuant to the policies of our Payment Processors;',
        'terms__transactions_listitem_6' => 'EquiLoomPRO may receive transaction confirmations or payment callbacks from fiat processors, but does not collect or store cardholder data, banking information, or other sensitive payment credentials.',
        'terms__text_7_transactions_4' => 'Where a fiat-based NFT purchase is made, the corresponding NFT is delivered to buyers wallet once full payment is received and confirmed by the Payment Processor. EquiLoomPRO does not guarantee delivery timelines and is not responsible for fiat payment errors, chargebacks, or regulatory holds.',
        'terms__title_8_risk_disclosure' => '8. Risk Disclosure',
        'terms__text_8_risk_1' => 'By using the Services in relation to the NFT Platform, you expressly acknowledge and agree that engaging in NFT minting, listing, trading, purchasing, and transacting — whether with cryptocurrency or fiat currency — carries significant and inherent risks. These risks include, without limitation:',
        'terms__risk_nft_listitem_1' => 'Volatility Risk: NFT valuations are highly speculative and subjective. Prices may fluctuate drastically and without notice, and there is no guarantee of resale, liquidity, or appreciation.',
        'terms__risk_nft_listitem_2' => 'Smart Contract Risk: NFTs listed or managed through the Service may be subject to smart contract code outside EquiLoomPRO\'s control. Smart contract bugs, exploits, or faulty logic may cause permanent loss of NFTs, funds, or associated metadata.',
        'terms__risk_nft_listitem_3' => 'Regulatory Risk: Laws and regulations governing digital assets, NFTs, or blockchain technologies are evolving and may impact your ability to hold, transfer, sell, or use NFTs acquired through the Services.',
        'terms__risk_nft_listitem_4' => 'Wallet/Custody Risk: You are solely responsible for maintaining access to your wallet. EquiLoomPRO cannot recover lost NFTs due to lost seed phrases, private keys, unauthorized transfers, malware, or other security compromises.',
        'terms__risk_nft_listitem_5' => 'Fiat Payment Risk: Payments processed by third-party providers may be subject to credit card network rules, compliance reviews, banking limits, delays, or cancellations without notice.',
        'terms__risk_nft_listitem_6' => 'Fraud & Counterfeit Risk: EquiLoomPRO does not guarantee the authenticity, legality, or market value of any NFT listed, minted, or purchased through the Service. It is your responsibility to perform due diligence before executing transactions.',
        'terms__text_8_risk_2' => 'You assume full responsibility for all risks associated with using the Services, and you waive any claim against EquiLoomPRO arising out of any loss, delay, fraud, misrepresentation, price fluctuation, or transaction failure.',
        'terms__title_9_royalties' => '9. Royalties and Promotions',
        'terms__text_9_royalties_1' => 'NFT Platform provided by EquiLoomPRO allows Creators to define Royalties at the time of minting, subject to the technical capabilities of the underlying blockchain. You acknowledge and agree that:',
        'terms__royalties_listitem_1' => 'Royalties are embedded in smart contracts and are automatically distributed upon secondary sale if supported by the receiving marketplace or wallet.',
        'terms__royalties_listitem_2' => 'EquiLoomPRO does not collect or enforce off-platform royalties and cannot guarantee royalty execution if assets are traded elsewhere.',
        'terms__royalties_listitem_3' => 'EquiLoomPRO may, from time to time, offer reward points, promotional credits, giveaways, or community incentives ("Rewards").',
        'terms__royalties_listitem_4' => 'Rewards have no intrinsic or fiat value, are not transferable or redeemable for cash, and may be changed, suspended, or terminated at EquiLoomPRO\'s sole discretion.',
        'terms__royalties_listitem_5' => 'Misuse of promotional features, including fraudulent sign-ups, referral abuse, or exploit attempts, may result in disqualification, suspension, or banning.',
        'terms__text_9_royalties_2' => 'You must comply with all published program rules, eligibility requirements, and deadlines to receive or redeem promotional benefits.',
        'terms__title_10_fees_taxes' => '10. Fees and Taxes',
        'terms__text_10_fees_1' => 'EquiLoomPRO may charge fees for the use of its Partner\'s services. These fees will be disclosed to you before you complete a transaction. By completing a transaction, you agree to pay any applicable fees. The fees offered to Users who access our Partner\'s services may be either higher or lower than when accessing our Partner\'s services directly on their website.',
        'terms__text_10_fees_2' => 'NFT Platform provided by EquiLoomPRO operates on a transparent and standardized revenue share model in which Creators receive 95% of primary NFT sale proceeds and EquiLoomPRO retains a 5% platform fee. Receival time of the sale proceeds for Creators may vary depending on chosen payment methods as well as Creators own financial institution chosen to receive the sale proceeds. This model applies to both crypto-based and fiat-based sales, subject to conversion and processing fees that Payment Processors or blockchain networks may separately charge.',
        'terms__text_10_fees_3' => 'You acknowledge and agree to the following:',
        'terms__fees_listitem_1' => 'Blockchain transactions may be subject to variable gas fees, which are paid directly to the network validators and not collected by EquiLoomPRO;',
        'terms__fees_listitem_2' => 'Fiat payments may include processing fees or foreign exchange fees imposed by third-party providers or your financial institution;',
        'terms__fees_listitem_3' => 'EquiLoomPRO does not offer refunds on successful NFT transactions;',
        'terms__fees_listitem_4' => 'NFT Platform fees are disclosed prior to purchase and are non-refundable once a transaction is confirmed;',
        'terms__fees_listitem_5' => 'All taxes arising from your use of the Services, including but not limited to value-added tax (VAT), income tax, capital gains tax, or self-employment tax, are your sole responsibility;',
        'terms__fees_listitem_6' => 'EquiLoomPRO does not issue tax forms, withhold taxes on your behalf, or report your activity to tax authorities unless required by law;',
        'terms__fees_listitem_7' => 'You are advised to consult with independent tax professionals regarding your obligations related to NFT sales, royalties, and crypto-to-fiat transactions.',
        'terms__text_10_fees_4' => 'You are fully responsible for determining whether, and to what extent, any taxes apply to any transactions associated with the Services. You must withhold, collect, report and remit the correct amounts of taxes to the appropriate tax authorities. We are not responsible for collecting these from you, for making any payments on your behalf, or for providing any reports relating to tax.',
        'terms__title_11_compliance' => '11. Compliance and Verification',
        'terms__text_11_compliance_1' => 'You agree to comply with all applicable laws and regulations related to the use of our Partner services or NFT Platform. Our Partner may require you to provide additional information and documentation to verify your identity and ensure compliance with their legal obligations in accordance with their Anti-Money-Laundering policy, and Payment Processors may require you to provide additional information and documentation to verify your identity and ensure compliance with their legal obligations in accordance with their Anti-Money-Laundering when using NFT Platform services.',
        'terms__text_11_compliance_2' => 'Creators may be required to provide additional information to EquiLoomPRO upon request to ensure compliance with these Terms of Use as well as applicable regulations.',
        'terms__title_12_ip_rights' => '12. Intellectual Property Rights and Content Licence',
        'terms__text_12_ip_1' => 'You retain full ownership and intellectual property rights to the original creative work ("NFT Content") that you mint, upload, or link to any NFT using the NFT Platform, provided you are the lawful rights holder or have obtained all necessary permissions, licences, and consents. However, by minting, listing, or uploading any NFT Content via NFT Platform, you hereby grant EquiLoomPRO a perpetual, worldwide, royalty-free, sublicensable, and non-exclusive licence to use, reproduce, display, publish, transmit, distribute, and otherwise exploit such NFT Content in connection with:',
        'terms__ip_listitem_1' => 'The operation, promotion, and improvement of the NFT Platform;',
        'terms__ip_listitem_2' => 'Social media marketing, promotional campaigns, and Creator spotlights;',
        'terms__ip_listitem_3' => 'Inclusion in any featured collections, drop pages, or community events;',
        'terms__ip_listitem_4' => 'Creating thumbnails, metadata previews, or media embeds for Users or search engines;',
        'terms__ip_listitem_5' => 'Public communication, research, archival, or internal analytics purposes.',
        'terms__text_12_ip_2' => 'You as a Creator warrant that your NFT Content:',
        'terms__ip_warrant_listitem_1' => 'Is your original work or is licensed appropriately for the intended use;',
        'terms__ip_warrant_listitem_2' => 'Does not infringe any third party\'s copyright, trademark, moral rights, publicity rights, or privacy rights;',
        'terms__ip_warrant_listitem_3' => 'Does not contain material that is defamatory, pornographic, unlawful, discriminatory, or misleading;',
        'terms__ip_warrant_listitem_4' => 'Complies with all applicable local and international IP laws and content regulations.',
        'terms__text_12_ip_3' => 'EquiLoomPRO does not act as an arbiter of intellectual property disputes. We may, at our discretion, remove content in response to takedown requests or court orders, and reserve the right to suspend or permanently restrict access for repeat infringers or Users involved in unauthorized use of copyrighted material.',
        'terms__text_12_ip_4' => 'All other content apart from NFT Content on this website, including but not limited to text, graphics, logos, images, audio, video, design, layout, software, code, and any other materials (collectively, "Content"), is the exclusive intellectual property of EquiLoomPRO and/or our Partner or its licensors and is protected by applicable copyright, trademark, and other intellectual property laws.',
        'terms__text_12_ip_5' => 'No part of the Content may be copied, reproduced, republished, uploaded, posted, transmitted, distributed, or used in any manner—whether in whole or in part, for commercial or non-commercial purposes—without the prior written consent of EquiLoomPRO.',
        'terms__text_12_ip_6' => 'Any unauthorized use of the Content may result in legal action, including but not limited to claims for damages and/or injunctive relief.',
        'terms__title_13_privacy' => '13. Privacy',
        'terms__text_13_privacy_1' => 'Your privacy is important to us. Please refer to our Privacy Policy for information on how we collect, use, and protect your personal data.',
        'terms__title_14_limitation' => '14. Limitation of Liability',
        'terms__text_14_limitation_1' => 'To the fullest extent permitted by law, EquiLoomPRO shall not be liable for any indirect, incidental, special, consequential, or punitive damages, or any loss of profits or revenues, whether incurred directly or indirectly, or any loss of data, use, goodwill, NFTs, security breaches, wallet hacks, smart contract failures, errors in fiat payment processing or delayed delivery of NFTs, downtime, bugs, software malfunctions, or service interruptions, actions of third-party wallets, marketplaces, or fiat processors or other intangible losses, resulting from:',
        'terms__limitation_listitem_1' => 'Your use or inability to use the services.',
        'terms__limitation_listitem_2' => 'Any unauthorized access to or use of our servers and/or any personal information stored therein.',
        'terms__limitation_listitem_3' => 'Any interruption or cessation of transmission to or from our services.',
        'terms__limitation_listitem_4' => 'Any bugs, viruses, trojan horses, or the like that may be transmitted to or through our services by any third party.',
        'terms__limitation_listitem_5' => 'Any errors or omissions in any content or for any loss or damage incurred as a result of the use of any content posted, emailed, transmitted, or otherwise made available through the services.',
        'terms__limitation_listitem_6' => 'Any wrongdoing, malfunction, intentional or unintentional fault by third party.',
        'terms__text_14_limitation_2' => 'EquiLoomPRO does not provide a virtual currency investment platform, sale, purchase or custody services, but simply offers access to its Partner\'s services for its Users and NFT Platform services as described herein.',
        'terms__title_15_indemnification' => '15. Indemnification',
        'terms__text_15_indemnification_1' => 'You agree to indemnify, defend, and hold harmless EquiLoomPRO, its affiliates, and their respective officers, directors, employees, and agents from and against any and all claims, liabilities, damages, losses, costs, expenses, or fees (including reasonable attorneys\' fees) arising from your use of the services or your violation of these Terms of Use.',
        'terms__title_16_termination' => '16. Termination',
        'terms__text_16_termination_1' => 'EquiLoomPRO reserves the right to suspend or terminate your account and access to the services at any time, without notice, for any reason, including if you breach these Terms of Use.',
        'terms__title_17_governing_law' => '17. Governing Law',
        'terms__text_17_governing_law_1' => 'These Terms of Use and any disputes arising out of or in connection with the use of the services shall be governed by and construed in accordance with the laws of the Philippines, without regard to its conflict of law provisions.',
        'terms__title_18_data_protection' => '18. Data Protection and Privacy',
        'terms__text_18_data_protection_1' => 'EquiLoomPRO complies with the Data Privacy Act of 2012. For details on how we collect, store, process, and share personal data, please refer to our Privacy Policy. By using the Services, you consent to the processing of your data in accordance with that policy.',
        'terms__title_19_force_majeure' => '19. Force Majeure',
        'terms__text_19_force_majeure_1' => 'EquiLoomPRO shall not be held liable for any failure or delay in performance due to circumstances beyond its reasonable control, including but not limited to natural disasters, cyberattacks, governmental actions, war, terrorism, labour disputes, or failures of third-party infrastructure, blockchain networks, or Payment Processors.',
        'terms__title_20_severability' => '20. Severability',
        'terms__text_20_severability_1' => 'If any provision of these Terms is deemed unlawful, void, or unenforceable under applicable law, that provision shall be severed from these Terms, and the remaining provisions shall remain in full force and effect.',
        'terms__title_21_contact_information' => '21. Contact Information',
        'terms__text_21_contact_information_1' => 'If you have any questions or concerns about these Terms of Use, please',
        'terms__contact_us' => 'contact us',
        'terms__title_22_entire_agreement' => '22. Entire Agreement',
        'terms__text_22_entire_agreement_1' => 'These Terms of Use constitute the entire agreement between you and EquiLoomPRO with respect to the use of the Services and supersede any prior agreements between you and EquiLoomPRO regarding the use of the Services.',
        'terms__text_22_entire_agreement_2' => 'By using our services, you acknowledge that you have read, understood, and agree to be bound by these Terms of Use.',
    ],
    'my' => [
        'language_iso' => 'en',
        'country_name' => 'MY',
        'locale' => 'en_MY',
        'locale_lang' => 'en-MY',
        'language_name' => 'English',
